#!/bin/bash
# ============================================================
# フィードバック管理機能 — 適用スクリプト
# omega-dev の dump-tracker-system リポジトリルートで実行
# ============================================================
set -e
echo "🚀 フィードバック管理機能 適用開始..."

echo "📝 backend/src/lib/firebase-admin.ts"
mkdir -p backend/src/lib
echo "" | base64 -d > backend/src/lib/firebase-admin.ts

echo "📝 backend/src/services/feedbackService.ts"
mkdir -p backend/src/services
echo "" | base64 -d > backend/src/services/feedbackService.ts

echo "📝 backend/src/controllers/feedbackController.ts"
mkdir -p backend/src/controllers
echo "" | base64 -d > backend/src/controllers/feedbackController.ts

echo "📝 backend/src/routes/feedbackRoutes.ts"
mkdir -p backend/src/routes
echo "" | base64 -d > backend/src/routes/feedbackRoutes.ts

echo "📝 frontend/cms/src/pages/FeedbackList.tsx"
mkdir -p frontend/cms/src/pages
echo "" | base64 -d > frontend/cms/src/pages/FeedbackList.tsx

echo "📝 frontend/cms/src/pages/FeedbackDetail.tsx"
mkdir -p frontend/cms/src/pages
echo "" | base64 -d > frontend/cms/src/pages/FeedbackDetail.tsx

# ============================================================
# 既存ファイルへのパッチ（Python で適用）
# ============================================================

python3 << 'INNER_PYEOF'
import re, sys

def read(p):
    with open(p, encoding="utf-8") as f: return f.read()

def write(p, s):
    with open(p, "w", encoding="utf-8") as f: f.write(s)
    print(f"✅ {p}")

# --- 1. constants.ts ---
p = "frontend/cms/src/utils/constants.ts"
src = read(p)
if "'feedback'" not in src:
    insert = """  {\n    id: 'feedback',\n    name: 'フィードバック管理',\n    path: '/feedback',\n    icon: 'MessageSquare',\n    adminOnly: true,  // ADMIN / MANAGER のみ\n  },\n  """
    src = src.replace("  {\n    id: 'gps-inspector',", insert + "  {\n    id: 'gps-inspector',")
    write(p, src)
else: print("⏭  constants.ts: 既に追加済み")

# --- 2. Sidebar.tsx ---
p = "frontend/cms/src/components/Layout/Sidebar.tsx"
src = read(p)
if "MessageSquare" not in src:
    src = src.replace("  Satellite,\n} from 'lucide-react';", "  Satellite,\n  MessageSquare,\n} from 'lucide-react';")
    src = src.replace("  Satellite: Satellite,\n};", "  Satellite: Satellite,\n  MessageSquare: MessageSquare,\n};")
    write(p, src)
else: print("⏭  Sidebar.tsx: 既に追加済み")

# --- 3. App.tsx ---
p = "frontend/cms/src/App.tsx"
src = read(p)
if "FeedbackList" not in src:
    src = src.replace("import GpsInspector from './pages/GpsInspector';",
        "import GpsInspector from './pages/GpsInspector';\nimport FeedbackList from './pages/FeedbackList';\nimport FeedbackDetail from './pages/FeedbackDetail';")
    src = src.replace(
        "              {/* GPS Inspector（管理者専用） */}\n              <Route path=\"gps-inspector\"",
        "              {/* フィードバック管理（ADMIN専用） */}\n              <Route path=\"feedback\" element={<FeedbackList />} />\n              <Route path=\"feedback/:id\" element={<FeedbackDetail />} />\n\n              {/* GPS Inspector（管理者専用） */}\n              <Route path=\"gps-inspector\"")
    write(p, src)
else: print("⏭  App.tsx: 既に追加済み")

# --- 4. routes/index.ts ---
p = "backend/src/routes/index.ts"
src = read(p)
if "feedbackRoutes" not in src:
    insert = """  {\n    name: 'feedbackRoutes',\n    path: '/feedback',\n    priority: 'normal' as const,\n    requireAuth: true,\n    description: 'フィードバック管理（ADMIN専用）',\n  },\n"""
    src = re.sub(r"(description: '客先マスタ管理'\s*\},\s*\n)", lambda m: m.group(0) + insert, src)
    write(p, src)
else: print("⏭  routes/index.ts: 既に追加済み")

# --- 5. app.ts ---
p = "backend/src/app.ts"
src = read(p)
if "feedbackRoutes" not in src:
    insert_block = """\n    // フィードバック管理ルート（ADMIN専用）\n    try {\n      const feedbackRoutes = require('./routes/feedbackRoutes').default || require('./routes/feedbackRoutes');\n      this.app.use('/api/v1/feedback', feedbackRoutes);\n      logger.info('✅ フィードバック管理APIルート登録完了: /api/v1/feedback');\n    } catch (error) {\n      logger.error('❌ feedbackRoutes 読み込み失敗', error);\n    }\n"""
    src = src.replace("    // 🎯 モバイルAPI統合", insert_block + "    // 🎯 モバイルAPI統合")
    write(p, src)
else: print("⏭  app.ts: 既に追加済み")

print("\n✅ 全パッチ適用完了!")
INNER_PYEOF

# ============================================================
# npm install (firebase-admin)
# ============================================================
echo ""
echo "📦 firebase-admin パッケージをインストール..."
cd backend && npm install firebase-admin --save && cd ..

# ============================================================
# TypeScript コンパイルチェック
# ============================================================
echo ""
echo "🔍 TypeScript コンパイルチェック (backend)..."
cd backend && npx tsc --noEmit 2>&1 | tee /tmp/tsc_backend.log
BACKEND_ERRORS=$(grep -c "error TS" /tmp/tsc_backend.log 2>/dev/null || echo 0)
cd ..

echo ""
echo "🔍 TypeScript コンパイルチェック (frontend/cms)..."
cd frontend/cms && npx tsc --noEmit 2>&1 | tee /tmp/tsc_cms.log
CMS_ERRORS=$(grep -c "error TS" /tmp/tsc_cms.log 2>/dev/null || echo 0)
cd ../..

echo ""
echo "===== コンパイル結果 ====="
echo "Backend エラー数: $BACKEND_ERRORS"
echo "CMS エラー数:     $CMS_ERRORS"

if [ "$BACKEND_ERRORS" -eq 0 ] && [ "$CMS_ERRORS" -eq 0 ]; then
    echo "✅ コンパイルエラー 0件 — GitHub Push 実行"
    git add -A
    git commit -m "feat: フィードバック管理機能追加 (FB-01/FB-02, Backlog連携)"
    git push origin main
    echo "🎉 GitHub Push 完了!"
else
    echo "❌ コンパイルエラーあり — Push 中止"
    echo "--- backend エラー ---"
    grep "error TS" /tmp/tsc_backend.log || true
    echo "--- cms エラー ---"
    grep "error TS" /tmp/tsc_cms.log || true
    exit 1
fi